import json

file_path = locals()['var_functions.query_db:32']
with open(file_path, 'r') as f:
    spring_docs = json.load(f)

counter = 0
project_list = []

for doc in spring_docs:
    text = doc['text']
    if 'Spring' in text and '2022' in text:
        lines = text.split('
')
        for line in lines:
            clean = line.strip()
            if clean and len(clean) > 5 and not clean.startswith('('):
                counter += 1
                if clean not in project_list:
                    project_list.append(clean)

result = {'total_lines': counter, 'unique_lines': len(project_list), 'sample': project_list[:10]}
print('__RESULT__:')
print(json.dumps(result))

